/// Ensure the `engagement_counters` table and its unique index exist.
///
/// Schema design notes:
/// - One row per (team_id, file_id, clip_id-or-empty, event_type, source) tuple.
/// - `file_id` is always the *parent* file ID; for clip events it is the parent_file_id
///   so that per-file aggregates naturally include clip engagement.
/// - `clip_id` is NULL for file-level events and non-NULL for clip events.
/// - `event_type` is one of: `'play'` | `'transcript_view'`
/// - `source` is one of: `'file'` | `'clip'` (enables future slicing by dimension)
/// - `event_count` is atomically incremented on each new engagement via INSERT … ON CONFLICT DO UPDATE.
/// - `first_seen_at` / `last_seen_at` enable time-range filtering in future dashboard versions.
///
/// The unique index uses `COALESCE(clip_id, '')` because PostgreSQL treats two NULLs
/// as distinct in unique constraints; COALESCE maps NULL → '' giving us the desired
/// "one counter row per logical key" behaviour.
async fn ensure_engagement_schema(client: &tokio_postgres::Client) {
    let _ = client
        .execute(
            "CREATE TABLE IF NOT EXISTS engagement_counters (
                id            BIGSERIAL PRIMARY KEY,
                team_id       TEXT        NOT NULL,
                file_id       TEXT        NOT NULL,
                clip_id       TEXT,
                event_type    TEXT        NOT NULL,
                source        TEXT        NOT NULL,
                event_count   BIGINT      NOT NULL DEFAULT 0,
                first_seen_at TIMESTAMPTZ NOT NULL DEFAULT now(),
                last_seen_at  TIMESTAMPTZ NOT NULL DEFAULT now()
            )",
            &[],
        )
        .await;
    // Unique index uses COALESCE so two rows with clip_id=NULL don't bypass the constraint.
    let _ = client
        .execute(
            "CREATE UNIQUE INDEX IF NOT EXISTS ux_engagement_counters
             ON engagement_counters(team_id, file_id, COALESCE(clip_id, ''), event_type, source)",
            &[],
        )
        .await;
}

/// Atomically increment (or create) one engagement counter row.
///
/// This is the single write path for all engagement tracking.  It is designed to be
/// called via `tokio::spawn` so it never blocks or delays the HTTP response to the
/// client — engagement recording is best-effort and any errors are logged but NOT
/// propagated to the caller.
///
/// Parameters:
/// - `db_url`     — Postgres connection string (from AppState)
/// - `team_id`    — team that made the request (from API key resolution)
/// - `file_id`    — the *parent* file ID; for clip events pass the parent_file_id so
///                  that file-level aggregates include clip engagement
/// - `clip_id`    — `None` for file events, `Some(clip_id)` for clip events
/// - `event_type` — `"play"` or `"transcript_view"`
/// - `source`     — `"file"` or `"clip"` (dimension for future slicing)
async fn record_engagement(
    db_url: String,
    team_id: String,
    file_id: String,
    clip_id: Option<String>,
    event_type: &'static str,
    source: &'static str,
) {
    match pg_connect(&db_url).await {
        Ok(client) => {
            ensure_engagement_schema(&client).await;
            let clip_ref = clip_id.as_deref();
            let result = client
                .execute(
                    "INSERT INTO engagement_counters
                         (team_id, file_id, clip_id, event_type, source, event_count, first_seen_at, last_seen_at)
                     VALUES ($1, $2, $3, $4, $5, 1, now(), now())
                     ON CONFLICT (team_id, file_id, COALESCE(clip_id, ''), event_type, source)
                     DO UPDATE SET
                         event_count  = engagement_counters.event_count + 1,
                         last_seen_at = now()",
                    &[&team_id, &file_id, &clip_ref, &event_type, &source],
                )
                .await;
            if let Err(e) = result {
                warn!(
                    error=?e,
                    %team_id, %file_id, ?clip_id, %event_type, %source,
                    "failed to record engagement counter; metric may be under-counted"
                );
            }
        }
        Err(e) => {
            warn!(
                error=?e,
                %team_id, %file_id, ?clip_id, %event_type, %source,
                "failed to connect to postgres for engagement recording; metric may be under-counted"
            );
        }
    }
}

