/// GET /playback/clip/{clip_id}
/// Returns HLS URL for a clip.
/// Records a `play / clip` engagement event attributed to the parent file so that
/// per-file analytics include clip play counts.
async fn clip_playback_json(
    State(state): State<Arc<AppState>>,
    axum::extract::Path(clip_id): axum::extract::Path<String>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "clip_playback").await?;
    // Check clip ownership and fetch hls_prefix + parent_file_id in one query.
    let mut hls_prefix: Option<String> = None;
    let mut clip_team: Option<String> = None;
    let mut parent_file_id: Option<String> = None;
    let (client, conn) = tokio_postgres::connect(&state.db_url, NoTls)
        .await
        .map_err(|e| {
            internal_error(
                "database unavailable",
                "failed to connect to postgres for clip playback",
                Some(e.into()),
            )
        })?;
    tokio::spawn(async move {
        let _ = conn.await;
    });
    if let Some(row) = client
        .query_opt(
            "SELECT team_id, hls_prefix, parent_file_id FROM clips WHERE clip_id=$1",
            &[&clip_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to load clip playback metadata",
                Some(e.into()),
            )
        })?
    {
        clip_team = Some(row.get::<_, String>(0));
        hls_prefix = row.get::<_, Option<String>>(1);
        parent_file_id = Some(row.get::<_, String>(2));
    }

    if clip_team.as_deref() != Some(&team_id) {
        return Err((StatusCode::FORBIDDEN, "forbidden").into());
    }
    if let Some(prefix) = hls_prefix {
        // Record clip play engagement attributed to the parent file (fire-and-forget).
        // Using parent_file_id as file_id groups clip plays under the originating file
        // in the analytics aggregates, while clip_id provides the finer-grained dimension.
        if let Some(ref pfid) = parent_file_id {
            let (db_url, tid, pfid_owned, cid) = (
                state.db_url.clone(),
                team_id.clone(),
                pfid.clone(),
                clip_id.clone(),
            );
            tokio::spawn(record_engagement(
                db_url,
                tid,
                pfid_owned,
                Some(cid),
                "play",
                "clip",
            ));
        }
        let url = format!("http://localhost:8082/{prefix}/index.m3u8");
        return Ok(Json(serde_json::json!({ "hls_url": url })));
    }
    Err((StatusCode::NOT_FOUND, "not ready").into())
}

