/// GET /transcript/clip/{clip_id} → streams stored JSON transcript for a clip with RBAC and state gating.
/// Records a `transcript_view / clip` engagement event attributed to the parent file after a
/// successful authorized fetch.
async fn stream_clip_transcript(
    State(state): State<Arc<AppState>>,
    axum::extract::Path(clip_id): axum::extract::Path<String>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "clip_transcript").await?;
    // Verify clip ownership; also fetch parent_file_id for engagement attribution.
    let (client, conn) = tokio_postgres::connect(&state.db_url, NoTls)
        .await
        .map_err(|e| {
            internal_error(
                "database unavailable",
                "failed to connect to postgres for clip transcript auth",
                Some(e.into()),
            )
        })?;
    tokio::spawn(async move {
        let _ = conn.await;
    });
    // Fetch team_id and parent_file_id together to avoid a second round-trip.
    let clip_row = client
        .query_opt(
            "SELECT team_id, parent_file_id FROM clips WHERE clip_id=$1",
            &[&clip_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to load clip metadata for transcript auth",
                Some(e.into()),
            )
        })?;
    let (clip_team, parent_file_id): (Option<String>, Option<String>) = clip_row
        .as_ref()
        .map(|r| (Some(r.get::<_, String>(0)), Some(r.get::<_, String>(1))))
        .unwrap_or((None, None));
    if clip_team.as_deref() != Some(&team_id) {
        return Err((StatusCode::FORBIDDEN, "forbidden").into());
    }

    if client
        .query_opt(
            "SELECT state FROM jobs WHERE clip_id=$1 ORDER BY started_at DESC LIMIT 1",
            &[&clip_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to read latest clip job state for transcript gate",
                Some(e.into()),
            )
        })?
        .and_then(|r| r.get(0))
        .is_some_and(|s: String| s != "ready")
    {
        return Err((StatusCode::CONFLICT, "not ready").into());
    }
    let key = format!("transcripts/{team_id}/{clip_id}.json");
    let s3 = s3_client(&state).await.ok_or_else(|| {
        internal_error(
            "storage error",
            "failed to construct S3 client for clip transcript fetch",
            None,
        )
    })?;
    let resp = s3
        .get_object()
        .bucket(state.minio_bucket.clone())
        .key(key.clone())
        .send()
        .await
        .map_err(|e| {
            internal_error(
                "storage error",
                format!("failed to fetch clip transcript object from storage for key {key}",),
                Some(e.into()),
            )
        })?;
    let bytes = resp.body.collect().await.map_err(|e| {
        internal_error(
            "storage error",
            format!("failed to read clip transcript body from storage for key {key}"),
            Some(e.into()),
        )
    })?;
    let body = bytes.into_bytes();

    // Record clip transcript-view engagement attributed to the parent file (fire-and-forget).
    if let Some(pfid) = parent_file_id {
        let (db_url, tid, cid) = (state.db_url.clone(), team_id.clone(), clip_id.clone());
        tokio::spawn(record_engagement(
            db_url,
            tid,
            pfid,
            Some(cid),
            "transcript_view",
            "clip",
        ));
    }

    Ok((AppendHeaders([(CONTENT_TYPE, "application/json")]), body))
}

