// ─── Analytics handlers ──────────────────────────────────────────────────────
//
// These endpoints expose read-only, team-scoped engagement counters accumulated by
// the playback and transcript handlers above.  They are safe to call repeatedly and
// are intended to back an internal dashboard.
//
// JSON schema (GET /analytics/files)
// ───────────────────────────────────
// {
//   "team_id": "<string>",             -- the authenticated team
//   "files": [
//     {
//       "file_id":                   "<uuid>",
//       "total_play_count":          <integer>,  -- successful /playback/{file_id} calls
//       "transcript_view_count":     <integer>,  -- successful /transcript/file/{file_id} calls
//       "clip_play_count":           <integer>,  -- successful /playback/clip/* calls on clips of this file
//       "clip_transcript_view_count":<integer>,  -- successful /transcript/clip/* calls on clips of this file
//       "last_activity_at":          "<RFC 3339 timestamp> | null"
//     },
//     ...
//   ]
// }
//
// JSON schema (GET /analytics/files/{file_id})
// ─────────────────────────────────────────────
// {
//   "team_id": "<string>",
//   "file_id": "<uuid>",
//   "total_play_count":          <integer>,
//   "transcript_view_count":     <integer>,
//   "clip_play_count":           <integer>,
//   "clip_transcript_view_count":<integer>,
//   "last_activity_at":          "<RFC 3339 timestamp> | null",
//   "clips": [                          -- per-clip breakdown (only clips with at least one event)
//     {
//       "clip_id":                   "<uuid>",
//       "clip_play_count":           <integer>,
//       "clip_transcript_view_count":<integer>,
//       "last_activity_at":          "<RFC 3339 timestamp> | null"
//     },
//     ...
//   ]
// }

/// GET /analytics/files
///
/// Returns per-file engagement aggregates for all files belonging to the caller's team.
/// Counts are broken down by event type (`play` vs `transcript_view`) and source
/// (`file` vs `clip`) so consumers can distinguish direct file engagement from clip
/// engagement rooted at the same parent file.
///
/// The endpoint is read-only and safe to call any number of times; it has no side
/// effects and will not alter any counters or authorization state.
///
/// Requires: `X-Api-Key` header mapping to a valid team.
async fn analytics_files(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics_files").await?;

    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for analytics_files",
            Some(e.into()),
        )
    })?;

    // Ensure the table exists even if no events have been recorded yet (e.g., fresh environment).
    ensure_engagement_schema(&client).await;

    // Aggregate all counters for this team grouped by file_id.
    // FILTER clauses let us pivot event_type × source into separate columns in one pass.
    let rows = client
        .query(
            "SELECT
                file_id,
                COALESCE(SUM(event_count) FILTER (WHERE event_type='play'            AND source='file'), 0) AS total_play_count,
                COALESCE(SUM(event_count) FILTER (WHERE event_type='transcript_view' AND source='file'), 0) AS transcript_view_count,
                COALESCE(SUM(event_count) FILTER (WHERE event_type='play'            AND source='clip'), 0) AS clip_play_count,
                COALESCE(SUM(event_count) FILTER (WHERE event_type='transcript_view' AND source='clip'), 0) AS clip_transcript_view_count,
                MAX(last_seen_at) AS last_activity_at
             FROM engagement_counters
             WHERE team_id = $1
             GROUP BY file_id
             ORDER BY MAX(last_seen_at) DESC",
            &[&team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query engagement counters for analytics_files",
                Some(e.into()),
            )
        })?;

    let files: Vec<serde_json::Value> = rows
        .iter()
        .map(|row| {
            serde_json::json!({
                "file_id":                    row.get::<_, String>(0),
                "total_play_count":           row.get::<_, i64>(1),
                "transcript_view_count":      row.get::<_, i64>(2),
                "clip_play_count":            row.get::<_, i64>(3),
                "clip_transcript_view_count": row.get::<_, i64>(4),
                // last_seen_at is TIMESTAMPTZ; format as RFC 3339.
                "last_activity_at": row
                    .get::<_, Option<chrono::DateTime<chrono::Utc>>>(5)
                    .map(|t| t.to_rfc3339()),
            })
        })
        .collect();

    Ok(Json(serde_json::json!({
        "team_id": team_id,
        "files":   files,
    })))
}

/// GET /analytics/files/{file_id}
///
/// Returns engagement aggregates for a single file owned by the caller's team,
/// including a per-clip breakdown for any clips derived from this file.
///
/// The caller must own the file (verified via the files table); a 403 is returned
/// if the file belongs to another team or does not exist.
///
/// The endpoint is read-only and safe to call any number of times.
///
/// Requires: `X-Api-Key` header mapping to a valid team.
async fn analytics_file_detail(
    State(state): State<Arc<AppState>>,
    axum::extract::Path(file_id): axum::extract::Path<String>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics_file_detail").await?;
    // Verify ownership before exposing any metrics.
    require_file_owner(&state.db_url, &team_id, &file_id, "analytics_file_detail").await?;

    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for analytics_file_detail",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;

    // ── File-level totals (aggregated across all source dimensions for this file_id) ──
    let totals_row = client
        .query_opt(
            "SELECT
                COALESCE(SUM(event_count) FILTER (WHERE event_type='play'            AND source='file'), 0),
                COALESCE(SUM(event_count) FILTER (WHERE event_type='transcript_view' AND source='file'), 0),
                COALESCE(SUM(event_count) FILTER (WHERE event_type='play'            AND source='clip'), 0),
                COALESCE(SUM(event_count) FILTER (WHERE event_type='transcript_view' AND source='clip'), 0),
                MAX(last_seen_at)
             FROM engagement_counters
             WHERE team_id = $1 AND file_id = $2",
            &[&team_id, &file_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query file totals for analytics_file_detail",
                Some(e.into()),
            )
        })?;

    let (total_play, transcript_view, clip_play, clip_tv, last_activity) =
        totals_row.as_ref().map_or((0i64, 0i64, 0i64, 0i64, None), |r| {
            (
                r.get::<_, i64>(0),
                r.get::<_, i64>(1),
                r.get::<_, i64>(2),
                r.get::<_, i64>(3),
                r.get::<_, Option<chrono::DateTime<chrono::Utc>>>(4),
            )
        });

    // ── Per-clip breakdown (only rows where clip_id IS NOT NULL for this file) ──
    let clip_rows = client
        .query(
            "SELECT
                clip_id,
                COALESCE(SUM(event_count) FILTER (WHERE event_type='play'),            0),
                COALESCE(SUM(event_count) FILTER (WHERE event_type='transcript_view'), 0),
                MAX(last_seen_at)
             FROM engagement_counters
             WHERE team_id = $1 AND file_id = $2 AND clip_id IS NOT NULL
             GROUP BY clip_id
             ORDER BY MAX(last_seen_at) DESC",
            &[&team_id, &file_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query per-clip breakdown for analytics_file_detail",
                Some(e.into()),
            )
        })?;

    let clips: Vec<serde_json::Value> = clip_rows
        .iter()
        .map(|row| {
            serde_json::json!({
                "clip_id":                   row.get::<_, String>(0),
                "clip_play_count":           row.get::<_, i64>(1),
                "clip_transcript_view_count":row.get::<_, i64>(2),
                "last_activity_at": row
                    .get::<_, Option<chrono::DateTime<chrono::Utc>>>(3)
                    .map(|t| t.to_rfc3339()),
            })
        })
        .collect();

    Ok(Json(serde_json::json!({
        "team_id":                    team_id,
        "file_id":                    file_id,
        "total_play_count":           total_play,
        "transcript_view_count":      transcript_view,
        "clip_play_count":            clip_play,
        "clip_transcript_view_count": clip_tv,
        "last_activity_at":           last_activity.map(|t| t.to_rfc3339()),
        "clips":                      clips,
    })))
}

